 31→var (
 32→	// relabelTargetLegacy allows targeting labels with legacy Prometheus character set, plus ${<var>} variables for dynamic characters from source the metrics.
 33→	relabelTargetLegacy = regexp.MustCompile(`^(?:(?:[a-zA-Z_]|\$(?:\{\w+\}|\w+))+\w*)+$`)
 34→
 35→	DefaultRelabelConfig = Config{
 36→		Action:      Replace,
 37→		Separator:   ";",
 38→		Regex:       MustNewRegexp("(.*)"),
 39→		Replacement: "$1",
 40→	}
 41→)
 42→
 43→// Action is the action to be performed on relabeling.
 44→type Action string
 45→
 46→const (
 47→	// Replace performs a regex replacement.
 48→	Replace Action = "replace"
 49→	// Keep drops targets for which the input does not match the regex.
 50→	Keep Action = "keep"
 51→	// Drop drops targets for which the input does match the regex.
 52→	Drop Action = "drop"
 53→	// KeepEqual drops targets for which the input does not match the target.
 54→	KeepEqual Action = "keepequal"
 55→	// DropEqual drops targets for which the input does match the target.
 56→	DropEqual Action = "dropequal"
 57→	// HashMod sets a label to the modulus of a hash of labels.
 58→	HashMod Action = "hashmod"
 59→	// LabelMap copies labels to other labelnames based on a regex.
 60→	LabelMap Action = "labelmap"
 61→	// LabelDrop drops any label matching the regex.
 62→	LabelDrop Action = "labeldrop"
 63→	// LabelKeep drops any label not matching the regex.
 64→	LabelKeep Action = "labelkeep"
 65→	// Lowercase maps input letters to their lower case.
 66→	Lowercase Action = "lowercase"
 67→	// Uppercase maps input letters to their upper case.
 68→	Uppercase Action = "uppercase"
 69→)
 70→
 71→// UnmarshalYAML implements the yaml.Unmarshaler interface.
 72→func (a *Action) UnmarshalYAML(unmarshal func(any) error) error {
 73→	var s string
 74→	if err := unmarshal(&s); err != nil {
 75→		return err
 76→	}
 77→	switch act := Action(strings.ToLower(s)); act {
 78→	case Replace, Keep, Drop, HashMod, LabelMap, LabelDrop, LabelKeep, Lowercase, Uppercase, KeepEqual, DropEqual:
 79→		*a = act
 80→		return nil
 81→	}
 82→	return fmt.Errorf("unknown relabel action %q", s)
 83→}
 84→
 85→// Config is the configuration for relabeling of target label sets.
 86→type Config struct {
 87→	// A list of labels from which values are taken and concatenated
 88→	// with the configured separator in order.
 89→	SourceLabels model.LabelNames `yaml:"source_labels,flow,omitempty" json:"source_labels,omitempty"`
 90→	// Separator is the string between concatenated values from the source labels.
 91→	Separator string `yaml:"separator,omitempty" json:"separator,omitempty"`
 92→	// Regex against which the concatenation is matched.
 93→	Regex Regexp `yaml:"regex,omitempty" json:"regex,omitempty"`
 94→	// Modulus to take of the hash of concatenated values from the source labels.
 95→	Modulus uint64 `yaml:"modulus,omitempty" json:"modulus,omitempty"`
 96→	// TargetLabel is the label to which the resulting string is written in a replacement.
 97→	// Regexp interpolation is allowed for the replace action.
 98→	TargetLabel string `yaml:"target_label,omitempty" json:"target_label,omitempty"`
 99→	// Replacement is the regex replacement pattern to be used.
100→	Replacement string `yaml:"replacement,omitempty" json:"replacement,omitempty"`
101→	// Action is the action to be performed for the relabeling.
102→	Action Action `yaml:"action,omitempty" json:"action,omitempty"`
103→	// NameValidationScheme to use when validating labels.
104→	NameValidationScheme model.ValidationScheme `yaml:"-" json:"-"`
105→}
106→
107→// UnmarshalYAML implements the yaml.Unmarshaler interface.
108→func (c *Config) UnmarshalYAML(unmarshal func(any) error) error {
109→	*c = DefaultRelabelConfig
110→	type plain Config
111→	if err := unmarshal((*plain)(c)); err != nil {
112→		return err
113→	}
114→	if c.Regex.Regexp == nil {
115→		c.Regex = MustNewRegexp("")
116→	}
117→	return nil
118→}
119→
120→func (c *Config) Validate(nameValidationScheme model.ValidationScheme) error {
121→	if c.Action == "" {
122→		return errors.New("relabel action cannot be empty")
123→	}
124→	if c.Modulus == 0 && c.Action == HashMod {
125→		return errors.New("relabel configuration for hashmod requires non-zero modulus")
126→	}
127→	if (c.Action == Replace || c.Action == HashMod || c.Action == Lowercase || c.Action == Uppercase || c.Action == KeepEqual || c.Action == DropEqual) && c.TargetLabel == "" {
128→		return fmt.Errorf("relabel configuration for %s action requires 'target_label' value", c.Action)
129→	}
130→
131→	// Relabel config validation scheme matches global if left blank.
132→	switch c.NameValidationScheme {
133→	case model.LegacyValidation, model.UTF8Validation:
134→	case model.UnsetValidation:
135→		c.NameValidationScheme = nameValidationScheme
136→	default:
137→		return fmt.Errorf("unknown relabel config name validation method specified, must be either '', 'legacy' or 'utf8', got %s", c.NameValidationScheme)
138→	}
139→
140→	if c.Action == Replace && !varInRegexTemplate(c.TargetLabel) && !c.NameValidationScheme.IsValidLabelName(c.TargetLabel) {
141→		return fmt.Errorf("%q is invalid 'target_label' for %s action", c.TargetLabel, c.Action)
142→	}
143→
144→	isValidLabelNameWithRegexVarFn := func(value string) bool {
145→		// UTF-8 allows ${} characters, so standard validation allow $variables by default.
146→		// TODO(bwplotka): Relabelling users cannot put $ and ${<...>} characters in metric names or values.
147→		// Design escaping mechanism to allow that, once valid use case appears.
148→		switch c.NameValidationScheme {
149→		case model.UTF8Validation:
150→			return c.NameValidationScheme.IsValidLabelName(value)
151→		default:
152→			// For legacy validation, use the legacy regex that allows $variables.
153→			return relabelTargetLegacy.MatchString(value)
154→		}
155→	}
156→	if c.Action == Replace && varInRegexTemplate(c.TargetLabel) && !isValidLabelNameWithRegexVarFn(c.TargetLabel) {
157→		return fmt.Errorf("%q is invalid 'target_label' for %s action", c.TargetLabel, c.Action)
158→	}
159→	if (c.Action == Lowercase || c.Action == Uppercase || c.Action == KeepEqual || c.Action == DropEqual) && !c.NameValidationScheme.IsValidLabelName(c.TargetLabel) {
160→		return fmt.Errorf("%q is invalid 'target_label' for %s action", c.TargetLabel, c.Action)
161→	}
162→	if (c.Action == Lowercase || c.Action == Uppercase || c.Action == KeepEqual || c.Action == DropEqual) && c.Replacement != DefaultRelabelConfig.Replacement {
163→		return fmt.Errorf("'replacement' can not be set for %s action", c.Action)
164→	}
165→	if c.Action == LabelMap && !isValidLabelNameWithRegexVarFn(c.Replacement) {
166→		return fmt.Errorf("%q is invalid 'replacement' for %s action", c.Replacement, c.Action)
167→	}
168→	if c.Action == HashMod && !c.NameValidationScheme.IsValidLabelName(c.TargetLabel) {
169→		return fmt.Errorf("%q is invalid 'target_label' for %s action", c.TargetLabel, c.Action)
170→	}
171→
172→	if c.Action == DropEqual || c.Action == KeepEqual {
173→		if c.Regex != DefaultRelabelConfig.Regex ||
174→			c.Modulus != DefaultRelabelConfig.Modulus ||
175→			c.Separator != DefaultRelabelConfig.Separator ||
176→			c.Replacement != DefaultRelabelConfig.Replacement {
177→			return fmt.Errorf("%s action requires only 'source_labels' and `target_label`, and no other fields", c.Action)
178→		}
179→	}
180→
181→	if c.Action == LabelDrop || c.Action == LabelKeep {
182→		if c.SourceLabels != nil ||
183→			c.TargetLabel != DefaultRelabelConfig.TargetLabel ||
184→			c.Modulus != DefaultRelabelConfig.Modulus ||
185→			c.Separator != DefaultRelabelConfig.Separator ||
186→			c.Replacement != DefaultRelabelConfig.Replacement {
187→			return fmt.Errorf("%s action requires only 'regex', and no other fields", c.Action)
188→		}
189→	}
190→
191→	return nil
192→}
