194→// Regexp encapsulates a regexp.Regexp and makes it YAML marshalable.
195→type Regexp struct {
196→	*regexp.Regexp
197→}
198→
199→// NewRegexp creates a new anchored Regexp and returns an error if the
200→// passed-in regular expression does not compile.
201→func NewRegexp(s string) (Regexp, error) {
202→	regex, err := regexp.Compile("^(?s:" + s + ")$")
203→	return Regexp{Regexp: regex}, err
204→}
205→
206→// MustNewRegexp works like NewRegexp, but panics if the regular expression does not compile.
207→func MustNewRegexp(s string) Regexp {
208→	re, err := NewRegexp(s)
209→	if err != nil {
210→		panic(err)
211→	}
212→	return re
213→}
214→
215→// UnmarshalYAML implements the yaml.Unmarshaler interface.
216→func (re *Regexp) UnmarshalYAML(unmarshal func(any) error) error {
217→	var s string
218→	if err := unmarshal(&s); err != nil {
219→		return err
220→	}
221→	r, err := NewRegexp(s)
222→	if err != nil {
223→		return err
224→	}
225→	*re = r
226→	return nil
227→}
228→
229→// MarshalYAML implements the yaml.Marshaler interface.
230→func (re Regexp) MarshalYAML() (any, error) {
231→	if re.String() != "" {
232→		return re.String(), nil
233→	}
234→	return nil, nil
235→}
236→
237→// UnmarshalJSON implements the json.Unmarshaler interface.
238→func (re *Regexp) UnmarshalJSON(b []byte) error {
239→	var s string
240→	if err := json.Unmarshal(b, &s); err != nil {
241→		return err
242→	}
243→	r, err := NewRegexp(s)
244→	if err != nil {
245→		return err
246→	}
247→	*re = r
248→	return nil
249→}
250→
251→// MarshalJSON implements the json.Marshaler interface.
252→func (re Regexp) MarshalJSON() ([]byte, error) {
253→	return json.Marshal(re.String())
254→}
255→
256→// IsZero implements the yaml.IsZeroer interface.
257→func (re Regexp) IsZero() bool {
258→	return re.Regexp == DefaultRelabelConfig.Regex.Regexp
259→}
260→
261→// String returns the original string used to compile the regular expression.
262→func (re Regexp) String() string {
263→	if re.Regexp == nil {
264→		return ""
265→	}
266→
267→	str := re.Regexp.String()
268→	// Trim the anchor `^(?s:` prefix and `)$` suffix.
269→	return str[5 : len(str)-2]
270→}
