272→// ProcessBuilder applies relabeling configurations (rules) to the labels in lb.
273→// The rules are applied in order of input. Returns false if the rule says to drop.
274→func ProcessBuilder(lb *labels.Builder, cfgs ...*Config) (keep bool) {
275→	for _, cfg := range cfgs {
276→		keep = relabel(cfg, lb)
277→		if !keep {
278→			return false
279→		}
280→	}
281→	return true
282→}
283→
284→func relabel(cfg *Config, lb *labels.Builder) (keep bool) {
285→	var va [16]string
286→	values := va[:0]
287→	if len(cfg.SourceLabels) > cap(values) {
288→		values = make([]string, 0, len(cfg.SourceLabels))
289→	}
290→	for _, ln := range cfg.SourceLabels {
291→		values = append(values, lb.Get(string(ln)))
292→	}
293→	val := strings.Join(values, cfg.Separator)
294→
295→	switch cfg.Action {
296→	case Drop:
297→		if cfg.Regex.MatchString(val) {
298→			return false
299→		}
300→	case Keep:
301→		if !cfg.Regex.MatchString(val) {
302→			return false
303→		}
304→	case DropEqual:
305→		if lb.Get(cfg.TargetLabel) == val {
306→			return false
307→		}
308→	case KeepEqual:
309→		if lb.Get(cfg.TargetLabel) != val {
310→			return false
311→		}
312→	case Replace:
313→		// Fast path to add or delete label pair.
314→		if val == "" && cfg.Regex == DefaultRelabelConfig.Regex &&
315→			!varInRegexTemplate(cfg.TargetLabel) && !varInRegexTemplate(cfg.Replacement) {
316→			lb.Set(cfg.TargetLabel, cfg.Replacement)
317→			break
318→		}
319→
320→		indexes := cfg.Regex.FindStringSubmatchIndex(val)
321→		// If there is no match no replacement must take place.
322→		if indexes == nil {
323→			break
324→		}
325→		target := string(cfg.Regex.ExpandString([]byte{}, cfg.TargetLabel, val, indexes))
326→		if !cfg.NameValidationScheme.IsValidLabelName(target) {
327→			break
328→		}
329→		res := cfg.Regex.ExpandString([]byte{}, cfg.Replacement, val, indexes)
330→		if len(res) == 0 {
331→			lb.Del(target)
332→			break
333→		}
334→		lb.Set(target, string(res))
335→	case Lowercase:
336→		lb.Set(cfg.TargetLabel, strings.ToLower(val))
337→	case Uppercase:
338→		lb.Set(cfg.TargetLabel, strings.ToUpper(val))
339→	case HashMod:
340→		hash := md5.Sum([]byte(val))
341→		// Use only the last 8 bytes of the hash to give the same result as earlier versions of this code.
342→		mod := binary.BigEndian.Uint64(hash[8:]) % cfg.Modulus
343→		lb.Set(cfg.TargetLabel, strconv.FormatUint(mod, 10))
344→	case LabelMap:
345→		lb.Range(func(l labels.Label) {
346→			if cfg.Regex.MatchString(l.Name) {
347→				res := cfg.Regex.ReplaceAllString(l.Name, cfg.Replacement)
348→				lb.Set(res, l.Value)
349→			}
350→		})
351→	case LabelDrop:
352→		lb.Range(func(l labels.Label) {
353→			if cfg.Regex.MatchString(l.Name) {
354→				lb.Del(l.Name)
355→			}
356→		})
357→	case LabelKeep:
358→		lb.Range(func(l labels.Label) {
359→			if !cfg.Regex.MatchString(l.Name) {
360→				lb.Del(l.Name)
361→			}
362→		})
363→	default:
364→		panic(fmt.Errorf("relabel: unknown relabel action type %q", cfg.Action))
365→	}
366→
367→	return true
368→}
369→
370→func varInRegexTemplate(template string) bool {
371→	return strings.Contains(template, "$")
372→}
